// Export list of all portal IDs
export const SUPPORTED_PORTALS = Object.keys(PORTAL_ADAPTERS);

// Get adapter by hostname
export function findAdapterByHostname(hostname) {
    for (const adapter of Object.values(PORTAL_ADAPTERS)) {
        if (adapter.match.hostnames.some(h => hostname.includes(h))) {
            return adapter;
        }
    }
    return null;
}

// Get adapter by URL pattern
export function findAdapterByUrl(url) {
    for (const adapter of Object.values(PORTAL_ADAPTERS)) {
        if (adapter.match.urlPatterns?.some(pattern => new RegExp(pattern).test(url))) {
            return adapter;
        }
    }
    return null;
}

// Get adapter by page content signature
export function findAdapterBySignature(pageContent) {
    for (const adapter of Object.values(PORTAL_ADAPTERS)) {
        if (adapter.match.pageSignatures?.some(sig => pageContent.includes(sig))) {
            return adapter;
        }
    }
    return null;
}

